local function newSkillEffect(item)
    local setting = SkillEffect.new()
    setting.id = item.id
    setting.name = item.name
    setting.duration = item.duration
    setting.width = item.width
    setting.height = item.height
    setting.density = item.density
    setting.effectType = 1
    return setting
end

local function initSkills(skills)
    for id, skill in pairs(skills) do
        local item = {}
        item.id = tonumber(skill.n_id)
        item.name = skill.n_name
        item.duration = tonumber(skill.n_duration)
        item.width = tonumber(skill.n_width)
        item.height = tonumber(skill.n_height)
        item.density = tonumber(skill.n_scale)
        HostApi.addSkillEffect(newSkillEffect(item))
    end
end

MonsterSkillConfig = {}

function MonsterSkillConfig:init(skills)
    initSkills(skills)
end

return SkillConfig